esqlQuery.esql:
TS metrics-ibmmq.otel-*
| STATS fdc_change = SUM(DELTA(ibmmq_qmgr_fdc_files))
    BY attributes.qmgr
// Alert when new FDC (First Failure Data Capture) files are generated
// FDC files indicate internal queue manager errors
// Any increase is significant and requires immediate investigation
| WHERE fdc_change IS NOT NULL AND fdc_change > 0
